/// Strip a trailing `-q<NN>` suffix.
fn strip_q(name: &str) -> &str {
    match name.rfind("-q") {
        Some(i) if i + 2 < name.len() && name[i + 2..].chars().all(|c| c.is_ascii_digit()) => &name[..i],
        _ => name,
    }
}

/// Canonical-name preference rank (lower = better). Plain `GTH-PBE` /
/// `GTH-SCAN` beat decorated variants (NLCC, GGA, …).
fn name_rank(name: &str, func: DbFunc) -> u8 {
    let base = strip_q(name).to_ascii_uppercase();
    match func {
        DbFunc::Pbe => {
            if base == "GTH-PBE" { 0 }
            else if base.contains("PBE") { 1 }
            else if base.contains("GGA") { 2 }
            else { 3 }
        }
        DbFunc::Scan => {
            if base == "GTH-SCAN" { 0 } else if base.contains("SCAN") { 1 } else { 2 }
        }
        DbFunc::AllElectron => 0,
    }
}

/// Look up the exact basis-set name for an element at a family prefix
/// (e.g. `"DZVP-MOLOPT-SR"`) and functional class. Returns `(name, q)`.
pub fn basis(element: &str, family_prefix: &str, func: DbFunc) -> Option<(&'static str, Option<u8>)> {
    let cands: Vec<&DbEntry> = DB
        .iter()
        .filter(|e| e.kind == DbKind::Basis && e.element == element && e.func == func)
        .collect();
    let canonical = format!("{family_prefix}-GTH");
    if let Some(e) = cands
        .iter()
        .filter(|e| strip_q(e.name) == canonical)
        .max_by_key(|e| e.q.unwrap_or(0))
    {
        return Some((e.name, e.q));
    }
    cands
        .iter()
        .filter(|e| e.name.starts_with(family_prefix))
        .min_by_key(|e| (name_rank(e.name, func), e.q.is_none() as usize, e.name.len()))
        .map(|e| (e.name, e.q))
}

/// Look up the pseudopotential name for an element and functional class,
/// preferring the canonical name and a valence count matching `q`.
pub fn potential(element: &str, func: DbFunc, q: Option<u8>) -> Option<&'static str> {
    let cands: Vec<&DbEntry> = DB
        .iter()
        .filter(|e| e.kind == DbKind::Pot && e.element == element && e.func == func)
        .collect();
    if let Some(want) = q {
        if let Some(e) = cands
            .iter()
            .filter(|e| e.q == Some(want))
            .min_by_key(|e| name_rank(e.name, func))
        {
            return Some(e.name);
        }
    }
    cands
        .iter()
        .min_by_key(|e| (name_rank(e.name, func), e.q.is_some() as usize, e.q.unwrap_or(0)))
        .map(|e| e.name)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn pbe_basis_exact_match() {
        assert_eq!(basis("Fe", "DZVP-MOLOPT-SR", DbFunc::Pbe), Some(("DZVP-MOLOPT-SR-GTH-q16", Some(16))));
        assert_eq!(basis("O", "DZVP-MOLOPT-SR", DbFunc::Pbe), Some(("DZVP-MOLOPT-SR-GTH-q6", Some(6))));
    }

    #[test]
    fn scan_basis_match() {
        let (name, q) = basis("O", "TZVP-MOLOPT", DbFunc::Scan).unwrap();
        assert_eq!(name, "TZVP-MOLOPT-SCAN-GTH-q6");
        assert_eq!(q, Some(6));
    }

    #[test]
    fn all_electron_pob_match() {
        let (name, _) = basis("Si", "pob-TZVP", DbFunc::AllElectron).unwrap();
        assert!(name.starts_with("pob-TZVP"), "got {name}");
    }

    #[test]
    fn potential_prefers_canonical() {
        // 必须取 GTH-PBE-q6 而非 GTH-NLCC-PBE-q6
        assert_eq!(potential("O", DbFunc::Pbe, Some(6)), Some("GTH-PBE-q6"));
        assert_eq!(potential("Fe", DbFunc::Pbe, Some(16)), Some("GTH-PBE-q16"));
        assert_eq!(potential("Fe", DbFunc::Scan, Some(16)), Some("GTH-SCAN-q16"));
        let ae = potential("O", DbFunc::AllElectron, None).unwrap();
        assert!(ae == "ALL" || ae == "ALLELECTRON", "got {ae}");
    }

    #[test]
    fn unknown_element_returns_none() {
        assert_eq!(basis("Xx", "DZVP-MOLOPT-SR", DbFunc::Pbe), None);
        assert_eq!(potential("Xx", DbFunc::Pbe, None), None);
    }
}
